const body = $input.first().json;
const toolCallList = body?.message?.toolCallList ?? [];
const call = body?.message?.call ?? {};

if (toolCallList.length === 0) {
  return [{
    json: {
      toolCallId: 'unknown',
      functionName: '__noop__',
      args: {},
      callerPhone: call?.customer?.number ?? '',
      callId: call?.id ?? ''
    }
  }];
}

const tc = toolCallList[0];
const args = typeof tc.function.arguments === 'string'
  ? JSON.parse(tc.function.arguments)
  : tc.function.arguments;

return [{
  json: {
    toolCallId: tc.id,
    functionName: tc.function.name,
    args: args,
    callerPhone: call?.customer?.number ?? args?.client_phone ?? '',
    callId: call?.id ?? ''
  }
}];

const parsedData = $('Parse Vapi Payload').first().json;
const args = parsedData.args || {};
const tz = $env.BUSINESS_TIMEZONE || 'America/New_York';
const startHour = parseInt($env.BUSINESS_START_HOUR || '9');
const endHour = parseInt($env.BUSINESS_END_HOUR || '17');
const durationMins = parseInt($env.SLOT_DURATION_MINUTES || '30');
const lookaheadDays = 7;

const baseDate = args.preferred_date ? new Date(args.preferred_date) : new Date();
baseDate.setHours(0, 0, 0, 0);

const windowEnd = new Date(baseDate.getTime() + lookaheadDays * 24 * 60 * 60 * 1000);

return [{
  json: {
    toolCallId: parsedData.toolCallId,
    callerPhone: parsedData.callerPhone,
    args: args,
    windowStart: baseDate.toISOString(),
    windowEnd: windowEnd.toISOString(),
    durationMins: durationMins,
    startHour: startHour,
    endHour: endHour,
    timezone: tz
  }
}];

const windowData = $('Calc Availability Window').first().json;
const events = $input.all().map(i => i.json);

const tz = windowData.timezone || 'America/New_York';
const startHour = windowData.startHour || 9;
const endHour = windowData.endHour || 17;
const durationMins = windowData.durationMins || 30;
const businessDays = ($env.BUSINESS_DAYS || '1,2,3,4,5').split(',').map(Number);
const slotMs = durationMins * 60 * 1000;

const busyPeriods = events
  .filter(e => e.start && (e.start.dateTime || e.start.date))
  .map(e => ({
    start: new Date(e.start.dateTime || e.start.date + 'T00:00:00').getTime(),
    end: new Date(e.end.dateTime || e.end.date + 'T23:59:59').getTime()
  }));

function getWeekdayISO(ts) {
  const day = new Intl.DateTimeFormat('en-US', { timeZone: tz, weekday: 'short' }).format(new Date(ts));
  return { Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6, Sun:7 }[day] || 7;
}

function getLocalHour(ts) {
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: tz, hour: 'numeric', hour12: false }).formatToParts(new Date(ts));
  return parseInt(parts.find(p => p.type === 'hour').value);
}

function isBusinessTime(ts) {
  const dow = getWeekdayISO(ts);
  const hr = getLocalHour(ts);
  return businessDays.includes(dow) && hr >= startHour && hr < endHour;
}

function isBusy(s, e) {
  return busyPeriods.some(b => s < b.end && e > b.start);
}

function fmtSlot(ts) {
  return new Intl.DateTimeFormat('en-US', {
    timeZone: tz, weekday: 'long', month: 'long', day: 'numeric',
    hour: 'numeric', minute: '2-digit', hour12: true
  }).format(new Date(ts));
}

const windowStart = new Date(windowData.windowStart).getTime();
const windowEnd = new Date(windowData.windowEnd).getTime();
const slots = [];
let cursor = windowStart;

while (cursor < windowEnd && slots.length < 8) {
  const slotEnd = cursor + slotMs;
  if (isBusinessTime(cursor) && isBusinessTime(slotEnd - 60000) && !isBusy(cursor, slotEnd)) {
    slots.push(fmtSlot(cursor));
    cursor += slotMs;
  } else {
    cursor += 30 * 60 * 1000;
  }
}

return [{
  json: {
    toolCallId: windowData.toolCallId,
    availableSlots: slots,
    timezone: tz
  }
}];

const { toolCallId, availableSlots } = $json;
let result;
if (!availableSlots || availableSlots.length === 0) {
  result = "I'm sorry, there are no available slots in the next 7 days. Would you like me to check a different time range, or can I take a message for the team?";
} else {
  const listed = availableSlots.slice(0, 5).join(', ');
  result = 'I have the following times available: ' + listed + '. Which one works best for you?';
}
return [{ json: { toolCallId, result } }];

const parsedData = $('Parse Vapi Payload').first().json;
const args = parsedData.args || {};
const tz = $env.BUSINESS_TIMEZONE || 'America/Denver';

const start = new Date(args.datetime);
const durationMins = args.duration_minutes || parseInt($env.SLOT_DURATION_MINUTES || '30');
const end = new Date(start.getTime() + durationMins * 60000);

const humanStart = new Intl.DateTimeFormat('en-US', {
  timeZone: tz, weekday: 'long', month: 'long', day: 'numeric',
  hour: 'numeric', minute: '2-digit', hour12: true
}).format(start);

const tzAbbr = new Intl.DateTimeFormat('en-US', { timeZone: tz, timeZoneName: 'short' })
  .formatToParts(start).find(p => p.type === 'timeZoneName')?.value || 'MST';

const noteParts = [];
if (args.reason_for_visit) noteParts.push('Reason: ' + args.reason_for_visit);
if (args.is_first_time === true) noteParts.push('STATUS: NEW CLIENT');
if (args.is_first_time === false) noteParts.push('STATUS: Returning client');
if (args.notes) noteParts.push(args.notes);
const notes = noteParts.join(' | ');

return [{
  json: {
    toolCallId: parsedData.toolCallId,
    callerPhone: parsedData.callerPhone,
    clientName: args.client_name || 'Client',
    clientPhone: args.client_phone || parsedData.callerPhone,
    service: args.service || 'Appointment',
    notes: notes,
    is_first_time: args.is_first_time,
    reason_for_visit: args.reason_for_visit || '',
    eventSummary: (args.service || 'Appointment') + ' - ' + (args.client_name || 'Client'),
    eventStart: start.toISOString(),
    eventEnd: end.toISOString(),
    humanStart: humanStart,
    tzAbbr: tzAbbr
  }
}];

const d = $('Prepare Booking Data').first().json;
return [{
  json: {
    toolCallId: d.toolCallId,
    result: 'Your ' + d.service + ' appointment has been booked for ' + d.humanStart + ' ' + d.tzAbbr + '. A confirmation text has been sent to ' + d.clientPhone + '. Is there anything else I can help you with?'
  }
}];

const parsedData = $('Parse Vapi Payload').first().json;
const args = parsedData.args || {};
const now = new Date();
const pastWindow = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);
const futureWindow = new Date(now.getTime() + 90 * 24 * 60 * 60 * 1000);

return [{
  json: {
    toolCallId: parsedData.toolCallId,
    callerPhone: parsedData.callerPhone,
    searchQuery: args.client_name || '',
    newDatetime: args.new_datetime,
    durationMins: args.duration_minutes || parseInt($env.SLOT_DURATION_MINUTES || '30'),
    clientName: args.client_name || 'Client',
    clientPhone: args.client_phone || parsedData.callerPhone,
    service: args.service || '',
    searchStart: pastWindow.toISOString(),
    searchEnd: futureWindow.toISOString()
  }
}];

const searchData = $('Prepare Reschedule Search').first().json;
const events = $input.all().map(i => i.json);
const tz = $env.BUSINESS_TIMEZONE || 'America/New_York';

const futureEvents = events.filter(e => {
  const eventStart = new Date(e.start?.dateTime || e.start?.date + 'T00:00:00');
  return eventStart >= new Date();
});

if (futureEvents.length === 0) {
  return [{
    json: {
      toolCallId: searchData.toolCallId,
      error: true,
      result: "I couldn't find an upcoming appointment for " + searchData.clientName + ". Could you confirm the name or give me more details about the appointment?"
    }
  }];
}

const target = futureEvents[0];
const newStart = new Date(searchData.newDatetime);
const newEnd = new Date(newStart.getTime() + searchData.durationMins * 60000);

const humanStart = new Intl.DateTimeFormat('en-US', {
  timeZone: tz, weekday: 'long', month: 'long', day: 'numeric',
  hour: 'numeric', minute: '2-digit', hour12: true
}).format(newStart);

const tzAbbr = new Intl.DateTimeFormat('en-US', { timeZone: tz, timeZoneName: 'short' })
  .formatToParts(newStart).find(p => p.type === 'timeZoneName')?.value || 'ET';

return [{
  json: {
    toolCallId: searchData.toolCallId,
    eventId: target.id,
    clientName: searchData.clientName,
    clientPhone: searchData.clientPhone,
    service: searchData.service || (target.summary || '').split(' - ')[0] || 'Appointment',
    newStart: newStart.toISOString(),
    newEnd: newEnd.toISOString(),
    humanStart: humanStart,
    tzAbbr: tzAbbr,
    error: false
  }
}];

const d = $('Pick Event to Reschedule').first().json;
return [{
  json: {
    toolCallId: d.toolCallId,
    result: d.error
      ? d.result
      : 'Your appointment has been successfully rescheduled to ' + d.humanStart + ' ' + d.tzAbbr + '. A text update has been sent to ' + d.clientPhone + '. Is there anything else I can help you with?'
  }
}];

const parsedData = $('Parse Vapi Payload').first().json;
const args = parsedData.args || {};
const now = new Date();
const pastWindow = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const futureWindow = new Date(now.getTime() + 90 * 24 * 60 * 60 * 1000);

return [{
  json: {
    toolCallId: parsedData.toolCallId,
    callerPhone: parsedData.callerPhone,
