    clientName: args.client_name || 'Client',
    clientPhone: args.client_phone || parsedData.callerPhone,
    searchStart: pastWindow.toISOString(),
    searchEnd: futureWindow.toISOString()
  }
}];

const searchData = $('Prepare Cancel Search').first().json;
const events = $input.all().map(i => i.json);
const tz = $env.BUSINESS_TIMEZONE || 'America/New_York';

const futureEvents = events.filter(e => {
  const t = new Date(e.start?.dateTime || e.start?.date + 'T00:00:00');
  return t >= new Date();
});

if (futureEvents.length === 0) {
  return [{
    json: {
      toolCallId: searchData.toolCallId,
      error: true,
      result: "I couldn't find an upcoming appointment for " + searchData.clientName + ". Could you double-check the name or the date of the appointment?"
    }
  }];
}

const target = futureEvents[0];
const eventStart = new Date(target.start?.dateTime || target.start?.date + 'T00:00:00');

const humanStart = new Intl.DateTimeFormat('en-US', {
  timeZone: tz, weekday: 'long', month: 'long', day: 'numeric',
  hour: 'numeric', minute: '2-digit', hour12: true
}).format(eventStart);

const tzAbbr = new Intl.DateTimeFormat('en-US', { timeZone: tz, timeZoneName: 'short' })
  .formatToParts(eventStart).find(p => p.type === 'timeZoneName')?.value || 'ET';

return [{
  json: {
    toolCallId: searchData.toolCallId,
    eventId: target.id,
    clientName: searchData.clientName,
    clientPhone: searchData.clientPhone,
    humanStart: humanStart,
    tzAbbr: tzAbbr,
    error: false
  }
}];

const d = $('Validate Cancel Event').first().json;
return [{
  json: {
    toolCallId: d.toolCallId,
    result: d.error
      ? d.result
      : 'Your appointment on ' + d.humanStart + ' ' + d.tzAbbr + ' has been successfully cancelled. A confirmation text has been sent. We hope to see you again — call us anytime to rebook!'
  }
}];

const parsedData = $('Parse Vapi Payload').first().json;
return [{
  json: {
    toolCallId: parsedData.toolCallId,
    result: "I'm sorry, I wasn't able to process that request. Could you please tell me what you'd like to do — book, reschedule, cancel an appointment, or check availability?"
  }
}];

const { toolCallId, result } = $json;
return [{
  json: {
    results: [{
      toolCallId: toolCallId || 'unknown',
      result: result || "I'm sorry, something went wrong. Please try again."
    }]
  }
}];

return [{
  json: {
    results: [{
      toolCallId: 'unknown',
      result: "I'm sorry, I encountered a technical issue. Please try again or call back in a moment."
    }]
  }
}];
